88:     @Inject
89:     public ConnectorsResource(
90:             Herder herder,
91:             RestServerConfig config,
92:             RestClient restClient,
93:             RestRequestTimeout requestTimeout
94:     ) {
95:         this.herder = herder;
96:         this.requestHandler = new HerderRequestHandler(restClient, requestTimeout);
97:         this.isTopicTrackingDisabled = !config.topicTrackingEnabled();
98:         this.isTopicTrackingResetDisabled = !config.topicTrackingResetEnabled();
