455:     // For testing only
456:     public void requestTimeout(long requestTimeoutMs) {
457:         this.requestTimeout.timeoutMs(requestTimeoutMs);
458:     }
459: 
460:     // For testing only
461:     public void healthCheckTimeout(long healthCheckTimeoutMs) {
462:         this.requestTimeout.healthCheckTimeoutMs(healthCheckTimeoutMs);
463:     }
464: 
465:     String determineAdvertisedProtocol() {
466:         String advertisedSecurityProtocol = config.advertisedListener();
467:         if (advertisedSecurityProtocol == null) {
468:             String listeners = config.rawListeners();
469: 
470:             if (listeners == null)
471:                 return PROTOCOL_HTTP;
472:             else
473:                 listeners = listeners.toLowerCase(Locale.ENGLISH);
474: 
475:             if (listeners.contains(String.format("%s://", PROTOCOL_HTTP)))
476:                 return PROTOCOL_HTTP;
477:             else if (listeners.contains(String.format("%s://", PROTOCOL_HTTPS)))
478:                 return PROTOCOL_HTTPS;
479:             else
480:                 return PROTOCOL_HTTP;
481:         } else {
482:             return advertisedSecurityProtocol.toLowerCase(Locale.ENGLISH);
483:         }
484:     }
485: 
486:     /**
487:      * Locate a Jetty connector for the standard (non-admin) REST API that uses the given protocol.
488:      * @param protocol the protocol for the connector (e.g., "http" or "https").
489:      * @return a {@link ServerConnector} for the server that uses the requested protocol, or
490:      * {@code null} if none exist.
491:      */
492:     ServerConnector findConnector(String protocol) {
493:         for (Connector connector : jettyServer.getConnectors()) {
494:             String connectorName = connector.getName();
495:             // We set the names for these connectors when instantiating them, beginning with the
496:             // protocol for the connector and then an underscore ("_"). We rely on that format here
497:             // when trying to locate a connector with the requested protocol; if the naming format
498:             // for the connectors we create is ever changed, we'll need to adjust the logic here
499:             // accordingly.
500:             if (connectorName.startsWith(protocol + "_") && !ADMIN_SERVER_CONNECTOR_NAME.equals(connectorName))
501:                 return (ServerConnector) connector;
502:         }
503: 
504:         return null;
505:     }
