540:     /**
541:      * Register header filter to ServletContextHandler.
542:      * @param context The servlet context handler
543:      */
544:     protected void configureHttpResponseHeaderFilter(ServletContextHandler context, String headerConfig) {
545:         FilterHolder headerFilterHolder = new FilterHolder(HeaderFilter.class);
546:         headerFilterHolder.setInitParameter("headerConfig", headerConfig);
547:         context.addFilter(headerFilterHolder, "/*", EnumSet.of(DispatcherType.REQUEST));
548:     }
